fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    let n = value.len();
    let mut available = (0..n).collect::<Vec<_>>();
    let mut total = 0;
    let mut active_count = 0;
    let mut used = vec![false; n];

    // Sort elements by value in descending order
    available.sort_by(|&a, &b| value[a].cmp(&value[b]));

    for i in 0..n {
        let idx = available[i];
        if used[idx] {
            continue;
        }

        // Check if we can activate this element
        if active_count < limit[idx] {
            // Activate the element
            total += value[idx];
            used[idx] = true;
            active_count += 1;

            // Deactivate all elements whose limit is <= active_count
            for j in 0..n {
                if !used[j] && limit[j] <= active_count {
                    used[j] = true;
                }
            }
        }
    }

    total
}
