fn solve(value: Vec<i64>, limit: Vec<i64>) -> i64 {
    let n = value.len();
    let mut available = (0..n).collect::<Vec<_>>();
    let mut total = 0;
    let mut active_count = 0;

    // Sort elements by value in descending order
    available.sort_by(|&a, &b| value[b].cmp(&value[a]));

    for i in 0..n {
        // Find the first element that can be activated
        let mut j = 0;
        while j < available.len() {
            let idx = available[j];
            if active_count < limit[idx] {
                // Activate this element
                total += value[idx];
                active_count += 1;
                available.remove(j);
                break;
            } else {
                j += 1;
            }
        }

        // After activation, mark all elements with limit <= active_count as inactive
        let mut to_remove = Vec::new();
        for &idx in &available {
            if limit[idx] <= active_count {
                to_remove.push(idx);
            }
        }
        for &idx in &to_remove {
            if let Some(pos) = available.iter().position(|&x| x == idx) {
                available.remove(pos);
            }
        }
    }

    total
}
