    let n = value.len();
    let mut available = (0..n).collect::<Vec<_>>();
    let mut total = 0;
    let mut active_count = 0;

    // Sort elements by value in descending order
    available.sort_by(|&a, &b| value[a].cmp(&value[b]));

    for i in 0..n {
        let idx = available[i];
        let val = value[idx];
        let lim = limit[idx];

        // Check if we can activate this element
        if active_count < lim {
            // Activate the element
